/**
 * Search available GPU machines with profile-aware filters
 * @summary Search GPU offers on Vast.ai
 */
export const getSearchOffersUrl = (params?: SearchOffersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/offers?${stringifiedParams}`
    : `/api/offers`;
};

export const searchOffers = async (
  params?: SearchOffersParams,
  options?: RequestInit,
): Promise<GpuOffer[]> => {
  return customFetch<GpuOffer[]>(getSearchOffersUrl(params), {
    ...options,
    method: "GET",
  });
};

